import React, { useState, useEffect } from 'react';
import {
  Box,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  CircularProgress,
  Alert,
  Grid,
  IconButton,
  Tooltip
} from '@mui/material';
import { Refresh } from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const HistoricoTrades = () => {
  const [trades, setTrades] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [countdown, setCountdown] = useState(30);
  const [autoRefresh, setAutoRefresh] = useState(true);
  const [stats, setStats] = useState({
    totalTrades: 0,
    winRate: 0,
    totalPnl: 0,
    winningTrades: 0,
    losingTrades: 0
  });

  const loadTrades = async () => {
    try {
      setLoading(true);
      setError(null);
      console.log('🔄 HistoricoTrades: Carregando trades fechados...');
      const response = await dashboardService.getClosedTrades();
      console.log('📊 HistoricoTrades: Resposta completa:', response);
      
      // Garantir que temos um array de trades
      // O backend retorna os trades em 'trades', não 'data'
      const tradesData = response.trades || [];
      console.log('✅ HistoricoTrades: Trades processados:', tradesData);
      console.log('📈 HistoricoTrades: Total de trades:', tradesData.length);
      setTrades(tradesData);
      
      // Calcular estatísticas apenas se houver trades
      if (tradesData.length > 0) {
        const winningTrades = tradesData.filter(trade => parseFloat(trade.pnl) > 0).length;
        const losingTrades = tradesData.filter(trade => parseFloat(trade.pnl) <= 0).length;
        const winRate = (winningTrades / tradesData.length) * 100;
        const totalPnl = tradesData.reduce((sum, trade) => sum + parseFloat(trade.pnl || 0), 0);

        setStats({
          totalTrades: tradesData.length,
          winRate,
          totalPnl,
          winningTrades,
          losingTrades
        });
      }
    } catch (error) {
      console.error('Erro ao carregar trades:', error);
      setError(error.message || 'Erro ao carregar histórico de trades');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadTrades();
  }, []);

  // Timer de 30 segundos para auto-refresh
  useEffect(() => {
    let interval;
    if (autoRefresh) {
      interval = setInterval(() => {
        setCountdown(prev => {
          if (prev <= 1) {
            loadTrades();
            return 30;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [autoRefresh]);

  const handleRefresh = () => {
    loadTrades();
    setCountdown(30);
  };

  const toggleAutoRefresh = () => {
    setAutoRefresh(!autoRefresh);
    if (!autoRefresh) {
      setCountdown(30);
    }
  };

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 8
    }).format(value);
  };

  const formatPercentage = (value) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'percent',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value / 100);
  };

  if (loading) {
    return (
      <Box sx={{ p: 3, textAlign: 'center' }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ p: 3 }}>
        <Alert 
          severity="error" 
          action={
            <IconButton
              color="inherit"
              size="small"
              onClick={handleRefresh}
            >
              <Refresh />
            </IconButton>
          }
        >
          {error}
        </Alert>
      </Box>
    );
  }

  return (
    <Box sx={{ width: '100%', bgcolor: 'background.paper', borderRadius: 1, overflow: 'hidden' }}>
      <Box sx={{ p: 2, borderBottom: 1, borderColor: 'divider', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h6" component="div" sx={{ color: 'text.primary' }}>
          Histórico de Trades
        </Typography>
        <Tooltip title="Atualizar histórico">
          <IconButton onClick={handleRefresh} size="small">
            <Refresh />
          </IconButton>
        </Tooltip>
      </Box>

      {/* Estatísticas */}
      <Grid container spacing={2} sx={{ p: 2 }}>
        <Grid item xs={12} sm={4} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Total de Trades</Typography>
            <Typography variant="h6">{stats.totalTrades}</Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={4} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Win Rate</Typography>
            <Typography variant="h6">{formatPercentage(stats.winRate)}</Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={4} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">PnL Total</Typography>
            <Typography variant="h6" color={stats.totalPnl >= 0 ? 'success.main' : 'error.main'}>
              {formatCurrency(stats.totalPnl)}
            </Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Trades Ganhos</Typography>
            <Typography variant="h6" color="success.main">{stats.winningTrades}</Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Trades Perdidos</Typography>
            <Typography variant="h6" color="error.main">{stats.losingTrades}</Typography>
          </Box>
        </Grid>
      </Grid>

      {/* Tabela de Trades */}
      <TableContainer component={Paper} sx={{ maxHeight: 400 }}>
        <Table stickyHeader>
          <TableHead>
            <TableRow>
              <TableCell align="center">Par</TableCell>
              <TableCell align="center">Lado</TableCell>
              <TableCell align="center">Tamanho</TableCell>
              <TableCell align="center">Alavancagem</TableCell>
              <TableCell align="center">Preço de Entrada</TableCell>
              <TableCell align="center">Preço de Saída</TableCell>
              <TableCell align="center">PnL</TableCell>
              <TableCell align="center">Margem Usada (USDT)</TableCell>
              <TableCell align="center">ROE%</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {trades.length === 0 ? (
              <TableRow>
                <TableCell colSpan={9} align="center">
                  <Typography variant="body2" color="text.secondary">
                    Nenhum trade fechado encontrado
                  </Typography>
                </TableCell>
              </TableRow>
            ) : (
              trades.map((trade, index) => (
                <TableRow key={index}>
                  <TableCell align="center">{trade.symbol}</TableCell>
                  <TableCell align="center" sx={{ color: trade.side === 'buy' ? 'success.main' : 'error.main' }}>
                    {trade.side === 'buy' ? 'LONG' : 'SHORT'}
                  </TableCell>
                  <TableCell align="center">{trade.size}</TableCell>
                  <TableCell align="center">{trade.leverage}x</TableCell>
                  <TableCell align="center">{trade.entry_price}</TableCell>
                  <TableCell align="center">{trade.exit_price}</TableCell>
                  <TableCell align="center" sx={{ color: parseFloat(trade.pnl) >= 0 ? 'success.main' : 'error.main' }}>
                    {formatCurrency(trade.pnl)}
                  </TableCell>
                  <TableCell align="center">
                    {trade.margin !== undefined && trade.margin !== null
                      ? formatCurrency(trade.margin)
                      : '-'}
                  </TableCell>
                  <TableCell align="center" sx={{ color: parseFloat(trade.roe) >= 0 ? 'success.main' : 'error.main' }}>
                    {formatPercentage(trade.roe)}
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
};

export default HistoricoTrades;
